/* PROCESS A: The Producer */
#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;string.h&gt;
#include &lt;fcntl.h&gt;
#include &lt;sys/mman.h&gt;
#include &lt;semaphore.h&gt;
#include &lt;unistd.h&gt;

typedef struct {
    int sensor_id;
    double temperature;
} Telemetry;

int main() {
    // 1. Create Shared Memory & Named Semaphore
    int fd = shm_open("/telemetry_shm", O_CREAT | O_RDWR, 0666);
    ftruncate(fd, sizeof(Telemetry));
    Telemetry *data = mmap(NULL, sizeof(Telemetry), PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);

    sem_t *lock = sem_open("/telemetry_lock", O_CREAT, 0666, 1);

    // 2. Safely mutate the Shared Memory
    printf("[Producer] Acquiring lock to write data...\n");
    sem_wait(lock);

    data->sensor_id = 42;
    data->temperature = 98.6;

    sem_post(lock);
    printf("[Producer] Data written. Lock released.\n");

    return 0;
}

// =========================================================================

/* PROCESS B: The Consumer */
// (Compile as a separate binary)
int main() {
    // 1. Open the existing Shared Memory & Semaphore
    int fd = shm_open("/telemetry_shm", O_RDWR, 0666);
    Telemetry *data = mmap(NULL, sizeof(Telemetry), PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    sem_t *lock = sem_open("/telemetry_lock", 0);

    // 2. Safely read the Shared Memory
    printf("[Consumer] Acquiring lock to read data...\n");
    sem_wait(lock);

    printf("[Consumer] Read Sensor %d: Temp %.1f\n", data->sensor_id, data->temperature);

    sem_post(lock);

    // 3. Cleanup Global Objects
    shm_unlink("/telemetry_shm");
    sem_unlink("/telemetry_lock");

    return 0;
}

#include &lt;sys/socket.h&gt;
#include &lt;sys/un.h&gt;
#include &lt;stdio.h&gt;

void start_local_server() {
    int fd = socket(AF_UNIX, SOCK_STREAM, 0);

    struct sockaddr_un addr = {0};
    addr.sun_family = AF_UNIX;
    strcpy(addr.sun_path, "/tmp/app.sock");

    // Engineer boots the server. It works perfectly.
    // The engineer kills the server (Ctrl+C) and runs it again.
    // DANGER: The second boot instantly fails here!
    if (bind(fd, (struct sockaddr*)&addr, sizeof(addr)) == -1) {
        perror("Bind failed");
    }
}
